use std::env;
use std::fs::{self, File};
use std::io::{self, Write};
use std::path::{Path, PathBuf};
use std::process;

const MINIGIT_DIR: &str = ".minigit";
const INDEX_FILE: &str = ".minigit/index";
const COMMIT_DIR: &str = ".minigit/commits";

fn main() {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        eprintln!("Usage: {} <command> [<args>]", args[0]);
        process::exit(1);
    }

    let command = &args[1];
    match command.as_str() {
        "init" => init(),
        "add" => {
            if args.len() < 3 {
                eprintln!("Usage: {} add <filename>", args[0]);
                process::exit(1);
            }
            add(&args[2]);
        }
        "commit" => {
            if args.len() < 3 {
                eprintln!("Usage: {} commit <message>", args[0]);
                process::exit(1);
            }
            commit(&args[2]);
        }
        _ => {
            eprintln!("Unknown command: {}", command);
            process::exit(1);
        }
    }
}

fn init() {
    if Path::new(MINIGIT_DIR).exists() {
        eprintln!("Repository already initialized");
        process::exit(1);
    }

    fs::create_dir(MINIGIT_DIR).unwrap();
    fs::create_dir(COMMIT_DIR).unwrap();
    File::create(INDEX_FILE).unwrap();

    println!("Initialized minigit repository");
}

fn add(filename: &str) {
    if !Path::new(MINIGIT_DIR).exists() {
        eprintln!("Not a minigit repository");
        process::exit(1);
    }

    if !Path::new(filename).exists() {
        eprintln!("File not found: {}", filename);
        process::exit(1);
    }

    let content = fs::read_to_string(filename).unwrap();
    let mut index = fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(INDEX_FILE)
        .unwrap();
    writeln!(index, "{}", filename).unwrap();

    println!("Added {}", filename);
}

fn commit(message: &str) {
    if !Path::new(MINIGIT_DIR).exists() {
        eprintln!("Not a minigit repository");
        process::exit(1);
    }

    let index_path = Path::new(INDEX_FILE);
    if !index_path.exists() {
        eprintln!("No files staged");
        process::exit(1);
    }

    let staged_files: Vec<String> = fs::read_to_string(index_path)
        .unwrap()
        .lines()
        .map(|s| s.to_string())
        .collect();

    if staged_files.is_empty() {
        eprintln!("No files staged");
        process::exit(1);
    }

    let commit_count = fs::read_dir(COMMIT_DIR).unwrap().count();
    let commit_id = commit_count + 1;
    let commit_file = format!("{}/{}", COMMIT_DIR, commit_id);

    let mut commit_content = format!("{}\n", message);
    for file in &staged_files {
        if Path::new(file).exists() {
            let content = fs::read_to_string(file).unwrap();
            commit_content.push_str(&format!("{}\n{}\n", file, content));
        }
    }

    fs::write(&commit_file, commit_content).unwrap();
    File::create(INDEX_FILE).unwrap();

    println!("Committed: {}", message);
}
